const body = $input.first().json;

// Ignora mensagens do próprio bot
if (body.data?.key?.fromMe === true) return [];

// Ignora grupos
const remoteJid = body.data?.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) return [];

const numero = remoteJid.replace('@s.whatsapp.net', '');
const tipoMensagem = body.data?.messageType || 'conversation';
const nomeContato = body.data?.pushName || 'Lead';
const messageKey = body.data?.key;

// Extrai conteúdo baseado no tipo
let mensagem = '';
let caption = '';
let fileName = '';
let mimetype = '';

switch (tipoMensagem) {
  case 'conversation':
    mensagem = body.data?.message?.conversation || '';
    break;
  case 'extendedTextMessage':
    mensagem = body.data?.message?.extendedTextMessage?.text || '';
    break;
  case 'audioMessage':
    mimetype = body.data?.message?.audioMessage?.mimetype || 'audio/ogg; codecs=opus';
    break;
  case 'imageMessage':
    caption = body.data?.message?.imageMessage?.caption || '';
    mimetype = body.data?.message?.imageMessage?.mimetype || 'image/jpeg';
    break;
  case 'documentMessage':
    fileName = body.data?.message?.documentMessage?.fileName || 'documento';
    mimetype = body.data?.message?.documentMessage?.mimetype || 'application/pdf';
    break;
  default:
    mensagem = body.data?.message?.conversation || body.data?.message?.extendedTextMessage?.text || '';
}

const temMidia = ['audioMessage', 'imageMessage', 'documentMessage'].includes(tipoMensagem);

if (!mensagem && !temMidia) return [];

return [{
  json: {
    numero, mensagem, nomeContato, tipoMensagem,
    messageKey, caption, fileName, mimetype, temMidia,
    timestamp: new Date().toISOString()
  }
}];

const rows = $input.all();
const config = {};
rows.forEach(row => { config[row.json.chave] = row.json.valor; });

const dados = $('Normaliza Mensagem').first().json;

const systemPrompt = `${config.prompt_sistema || ''}

OBJETIVO: ${config.objetivo || ''}
TONALIDADE: ${config.tonalidade || ''}
INSTRUÇÕES: ${config.instrucoes_comunicacao || ''}

CRITÉRIOS DE QUALIFICAÇÃO (mínimo 3):
${config.criterios_qualificacao || ''}

CAPACIDADES ESPECIAIS:
- Você pode OUVIR ÁUDIOS: quando o lead enviar um áudio, você receberá a transcrição
- Você pode VER IMAGENS: quando o lead enviar uma foto/imagem, você receberá a descrição detalhada
- Você pode LER DOCUMENTOS: quando o lead enviar um PDF ou documento, você receberá o conteúdo extraído
- Você pode PESQUISAR NA INTERNET: use a ferramenta busca_web para verificar legislação, jurisprudência e informações atualizadas
- Sempre confirme o recebimento de mídias de forma natural

QUANDO QUALIFICADO:
- Responda: ${config.msg_qualificado || 'Vou encaminhar seu caso ao advogado.'}
- Inclua JSON: \`\`\`json\n{"qualificado":true,"nome":"...","celular":"...","tese":"...","resumo":"..."}\n\`\`\`

QUANDO NÃO QUALIFICADO:
- Responda: ${config.msg_desqualificado || 'Agradecemos o contato!'}
- Inclua: \`\`\`json\n{"qualificado":false,"motivo":"..."}\n\`\`\`

REGRAS:
- Faça uma pergunta por vez
- Nunca prometa resultado
- Nunca dê consultoria jurídica
- Consulte a base de conhecimento e a web antes de responder dúvidas`;

return [{ json: { ...dados, config, systemPrompt } }];

const mediaData = $input.first().json;
const normaliza = $('Normaliza Mensagem').first().json;
const mimetype = mediaData.mimetype || normaliza.mimetype || 'audio/ogg';

// Converte base64 para binary no formato n8n
return [{
  json: { model: 'whisper-1', language: 'pt' },
  binary: {
    audio: {
      data: mediaData.base64,
      mimeType: mimetype,
      fileName: 'audio.ogg'
    }
  }
}];

const whisperResult = $input.first().json;
const normaliza = $('Normaliza Mensagem').first().json;
const sessao = $('Busca Histórico').first().json;

const transcricao = whisperResult.text || 'Áudio não reconhecido';

return [{
  json: {
    mensagemProcessada: `[Áudio do lead]: ${transcricao}`,
    tipoOriginal: 'audioMessage',
    numero: normaliza.numero,
    sessaoRow: sessao
  }
}];

const mediaData = $input.first().json;
const normaliza = $('Normaliza Mensagem').first().json;
const mimetype = mediaData.mimetype || normaliza.mimetype || 'image/jpeg';
const caption = normaliza.caption || '';

// Monta body para GPT-4o Vision
const requestBody = {
  model: 'gpt-4o',
  messages: [{
    role: 'user',
    content: [
      {
        type: 'text',
        text: `Analise esta imagem com atenção. ${caption ? 'Legenda enviada: ' + caption + '. ' : ''}Se for um documento (carteira de trabalho, CNIS, carta do INSS, exame médico, etc.), extraia TODOS os dados visíveis de forma estruturada. Se for uma foto comum, descreva o que vê.`
      },
      {
        type: 'image_url',
        image_url: { url: `data:${mimetype};base64,${mediaData.base64}` }
      }
    ]
  }],
  max_tokens: 2000
};

return [{ json: { requestBody } }];

const visionResult = $input.first().json;
const normaliza = $('Normaliza Mensagem').first().json;
const sessao = $('Busca Histórico').first().json;

const descricao = visionResult.choices?.[0]?.message?.content || 'Imagem recebida mas não foi possível analisar';

return [{
  json: {
    mensagemProcessada: `[Imagem enviada pelo lead]: ${descricao}`,
    tipoOriginal: 'imageMessage',
    numero: normaliza.numero,
    sessaoRow: sessao
  }
}];

const mediaData = $input.first().json;
const normaliza = $('Normaliza Mensagem').first().json;
const sessao = $('Busca Histórico').first().json;
const fileName = normaliza.fileName || 'documento';
const mimetype = mediaData.mimetype || normaliza.mimetype || '';

let texto = '';

// Tenta extrair texto básico do documento
try {
  if (mimetype.includes('text/') || mimetype.includes('csv')) {
    // Documentos de texto simples
    texto = Buffer.from(mediaData.base64, 'base64').toString('utf8');
  } else {
    // Para PDFs e outros, tenta extrair texto legível
    const buffer = Buffer.from(mediaData.base64, 'base64');
    const raw = buffer.toString('latin1');
    // Extrai strings entre parênteses (comum em PDFs)
    const matches = raw.match(/\(([^)]{2,})\)/g) || [];
    texto = matches
      .map(m => m.slice(1, -1))
      .filter(t => /[a-zA-ZÀ-ÿ0-9]/.test(t) && t.length > 2)
      .join(' ')
      .substring(0, 3000);
  }
} catch(e) {
  texto = '';
}

if (!texto || texto.length < 20) {
  texto = `Documento "${fileName}" recebido (${mimetype}). Não foi possível extrair texto automaticamente. Pergunte ao lead sobre o conteúdo do documento.`;
} else {
  texto = `Conteúdo extraído do documento "${fileName}": ${texto}`;
}

return [{
  json: {
    mensagemProcessada: `[Documento enviado]: ${texto}`,
    tipoOriginal: 'documentMessage',
    numero: normaliza.numero,
    sessaoRow: sessao
  }
}];

const normaliza = $('Normaliza Mensagem').first().json;
const sessao = $input.first().json;

return [{
  json: {
    mensagemProcessada: normaliza.mensagem,
    tipoOriginal: normaliza.tipoMensagem,
    numero: normaliza.numero,
    sessaoRow: sessao
  }
}];

const dados = $('Monta System Prompt').first().json;
const item = $input.first().json;

let historico = [];
try {
  historico = JSON.parse(item.sessaoRow?.historico || '[]');
} catch(e) { historico = []; }

// Adiciona a mensagem processada ao histórico
historico.push({
  role: 'user',
  content: item.mensagemProcessada
});

const historicoTexto = historico
  .map(h => `${h.role === 'user' ? 'Lead' : 'Agente'}: ${h.content}`)
  .join('\n');

return [{
  json: {
    ...dados,
    mensagemProcessada: item.mensagemProcessada,
    tipoOriginal: item.tipoOriginal,
    historico,
    historicoTexto
  }
}];

