const respostaAgente = $input.first().json.output || '';
const normaliza = $('Normaliza Mensagem').first().json;
const config = $('Monta System Prompt').first().json.config;
const tipoOriginal = $('Monta Histórico').first().json.tipoOriginal;

let dadosQualificacao = null;
let qualificado = null;

// Extrai JSON da resposta
try {
  const match = respostaAgente.match(/```json([\s\S]*?)```/);
  if (match) {
    dadosQualificacao = JSON.parse(match[1].trim());
    qualificado = dadosQualificacao.qualificado === true;
  }
} catch(e) {}

// Remove o JSON do texto que vai ao lead
const textoParaLead = respostaAgente.replace(/```json[\s\S]*?```/g, '').trim();

// Monta relatório formatado
let relatorio = null;
if (qualificado && dadosQualificacao) {
  const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
  relatorio = `🟢 *LEAD QUALIFICADO — SDR CLAUDE MARKA*\n\n`
    + `👤 *Nome:* ${dadosQualificacao.nome || 'Não informado'}\n`
    + `📱 *Celular:* ${dadosQualificacao.celular || normaliza.numero}\n`
    + `⚖️ *Tese:* ${dadosQualificacao.tese || 'Não identificada'}\n`
    + `📋 *Resumo:* ${dadosQualificacao.resumo || 'Ver histórico'}\n`
    + `🕐 *Atendimento:* ${agora}`;
}

return [{
  json: {
    numero: normaliza.numero,
    textoParaLead,
    qualificado,
    dadosQualificacao,
    relatorio,
    tipoOriginal,
    numeroDestino: config?.numero_destino
  }
}];

const binaryData = $input.first().binary?.data;
const numero = $('Processa Resposta').first().json.numero;

if (!binaryData) {
  return [{ json: { numero, erro: 'Sem dados de áudio' } }];
}

const audioBase64 = binaryData.data;

return [{
  json: {
    numero,
    audioBase64
  }
}];

const historico = $('Monta Histórico').first().json.historico;
const respostaAgente = $('Agente SDR — Claude Marka').first().json.output || '';
const numero = $('Normaliza Mensagem').first().json.numero;

historico.push({ role: 'assistant', content: respostaAgente });
const historicoTrimmed = historico.slice(-30);

return [{
  json: {
    numero_whatsapp: numero,
    historico: JSON.stringify(historicoTrimmed),
    atualizado_em: new Date().toISOString()
  }
}];
